// Search by value - returns node or NULL
struct Node* search(struct Node *head, int key) {
 struct Node *current = head;

 while(current != NULL) {
 if(current->data == key) {
 return current; // Found
 }
 current = current->next;
 }
 return NULL; // Not found
}

// Search by value - returns position (0-indexed)
int searchPosition(struct Node *head, int key) {
 struct Node *current = head;
 int position = 0;

 while(current != NULL) {
 if(current->data == key) {
 return position;
 }
 position++;
 current = current->next;
 }
 return -1; // Not found
}

